let taskDescription = $json.task?.description || $json.description || '';
// Fallback: if task came through as {raw_output: '...'}, extract descriptions from it
if (!taskDescription && $json.task?.raw_output) {
  const raw = $json.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) {
    taskDescription = raw;
  }
}
const previousFeedback = $json.previous_feedback || '';
const feedbackSection = previousFeedback ? `\n\nPREVIOUS REVIEW FEEDBACK (you MUST address all of these):\n${previousFeedback}` : '';
const existingFiles = $json.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nEXISTING PROJECT FILES (read these carefully — modify or extend, do NOT rewrite files that do not need changes):\n' +
    existingFiles.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n')
  : '';
return [{
  json: {
    model: 'local-model',
    messages: [{
      role: 'user',
      content: `You are a Senior Full-Stack Developer. Output ONLY the files that need to be created or changed. Do not output files that are already correct.\n\nTech Stack: TypeScript, Node.js/Express, React/Vite, PostgreSQL/Prisma\n\nFor EACH file you need to create or modify, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files that this task requires you to create or change\n- Output complete file content (not diffs)\n- No explanations, no numbered lists, no prose — ONLY the file blocks${feedbackSection}${existingFilesSection}\n\nTask:\n${taskDescription}`
    }],
    temperature: 0.7,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 1.5,
    max_tokens: 16000
  }
}];

const raw = $json.choices[0].message.content || '';
// Strip thinking - handle both <think>...</think> and bare text ending with </think>
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|Dockerfile|gitignore))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path) && fileContent.trim().length > 20) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
return [{ json: { files } }];
